#include <bits/stdc++.h>
using namespace std;
int t,n,k,a[100005];
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&k);
        int mx=0;
        long long sum=0;
        for(int i=1;i<=n;i++){
            scanf("%d",&a[i]);
            mx=max(mx,a[i]),sum+=mx;
        }
        if(n==2)
        	if(k%2==0)
        		printf("%lld\n",sum);
        	else{
        		swap(a[1],a[2]);
        		printf("%lld\n",1LL*(a[1]+max(a[1],a[2])));
			}
        else if(k>0)
            printf("%lld\n",1LL*mx*n);
        else
            printf("%lld\n",sum);
    }
    return 0;
}
